{
  "summary": "This paper proposes Contrastive Novelty Learning (CNL), a novel approach for open-set selective classification in text that leverages large language models to generate semantically novel out-of-distribution examples and trains classifiers with a contrastive confidence loss to improve detection and abstention on novel classes. Extensive experiments on multiple NLP datasets demonstrate improved OOD detection and selective classification performance without sacrificing in-distribution accuracy.",
  "strengths": [
    {
      "point": "Innovative use of large language models for generating novel class labels and examples",
      "evidence": "The paper introduces Novelty Prompting, a two-stage LLM prompting technique that generates plausible and semantically novel OOD examples, improving robustness to novel classes."
    },
    {
      "point": "Contrastive Confidence Loss that encourages relative confidence ordering",
      "evidence": "CCL penalizes cases where OOD confidence exceeds ID confidence, allowing flexible calibration that preserves ID accuracy while improving OOD detection."
    },
    {
      "point": "Strong empirical results across multiple datasets and architectures",
      "evidence": "CNL improves AUAC by 2.3% and AUROC by 5.5% over strong baselines on 14 splits from 4 NLP datasets, and generalizes across BERT and RoBERTa variants."
    },
    {
      "point": "Modular approach compatible with existing classifiers and training objectives",
      "evidence": "The method does not require architectural changes and can be combined with other confidence metrics or training losses."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to recent state-of-the-art NLP OOD detection methods",
      "evidence": "The paper omits baselines such as energy-based models and Mahalanobis distance detectors, limiting contextualization of empirical gains."
    },
    {
      "point": "Insufficient quantitative and ablative analysis on thesaurus-based filtering and generated example quality",
      "evidence": "No semantic similarity metrics or ablations assess the impact of filtering synonyms or the linguistic quality and diversity of generated examples."
    },
    {
      "point": "Limited evaluation metrics, missing calibration measures despite focus on confidence calibration",
      "evidence": "Evaluation excludes Expected Calibration Error or Brier score, which would directly evidence improved confidence estimates."
    },
    {
      "point": "Reproducibility concerns due to missing prompt engineering and training hyperparameters",
      "evidence": "Details on prompt templates, generation parameters, training batch composition, and sampling strategies for contrastive loss are absent."
    },
    {
      "point": "No empirical analysis on borderline or ambiguous novel examples",
      "evidence": "Claims of robustness to noisy novel examples lack experimental validation with ambiguous or semantically overlapping classes."
    },
    {
      "point": "Limited generalizability demonstrated only on single-label English text classification",
      "evidence": "No experiments on multi-label, hierarchical, cross-domain, or cross-lingual settings, restricting applicability claims."
    },
    {
      "point": "No discussion of computational cost, scalability, or ethical considerations of using large LLMs",
      "evidence": "The paper does not analyze runtime, cost, or potential biases introduced by synthetic data generation."
    },
    {
      "point": "Ambiguity in training procedure and confidence score definition",
      "evidence": "Unclear how generated examples are integrated during training and which confidence metric is used for the contrastive loss."
    }
  ],
  "questions": [
    {
      "question": "How does CNL perform compared to recent energy-based or Mahalanobis OOD detection methods in NLP?",
      "motivation": "Understanding relative performance would clarify CNL's novelty and practical advantages."
    },
    {
      "question": "What is the impact of thesaurus-based filtering on the diversity and utility of generated novel labels?",
      "motivation": "Quantifying this would validate the heuristic and guide future improvements in novelty prompting."
    },
    {
      "question": "Can the method be extended to multi-label, hierarchical, or cross-lingual classification tasks?",
      "motivation": "Broader applicability is critical for real-world deployment across diverse NLP scenarios."
    },
    {
      "question": "What are the computational and ethical trade-offs of relying on large LLMs for synthetic data generation?",
      "motivation": "Assessing cost and risks is important for practical adoption and responsible AI development."
    },
    {
      "question": "How sensitive is CNL to the number and semantic diversity of generated novel labels and examples?",
      "motivation": "Understanding sensitivity informs generation budget allocation and robustness."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
